import sys
it = iter(sys.stdin.read().split())
numCourses = int(next(it))
numPrerequisites = int(next(it))
prerequisites = [[int(next(it)), int(next(it))] for _ in range(numPrerequisites)]
def canFinish(numCourses, prerequisites):
    graph = [[] for _ in range(numCourses)]
    visited = [0 for _ in range(numCourses)]
    for x, y in prerequisites:
        graph[x].append(y)
    def dfs(i):
        if visited[i] == -1:
            return False
        if visited[i] == 1:
            return True
        visited[i] = -1
        for j in graph[i]:
            if not dfs(j):
                return False
        visited[i] = 1
        return True
    for i in range(numCourses):
        if not dfs(i):
            return 0
    return 1
print(canFinish(numCourses, prerequisites))

